(()=>{let t=self;t.addEventListener("push",i=>{if(i.data)try{let o=i.data.json(),n={body:o.body||"Tienes un traslado programado.",icon:"/icon-192x192.png",badge:"/icon-192x192.png",vibrate:[100,50,100],data:{url:o.url||"/"}};i.waitUntil(t.registration.showNotification(o.title||"Recordatorio TourFlow",n))}catch(n){let o=i.data.text();i.waitUntil(t.registration.showNotification("Recordatorio TourFlow",{body:o,icon:"/icon-192x192.png",badge:"/icon-192x192.png",vibrate:[100,50,100],data:{url:"/"}}))}}),t.addEventListener("notificationclick",i=>{i.notification.close();let o=i.notification.data?.url||"/";i.waitUntil(t.clients.matchAll({type:"window",includeUncontrolled:!0}).then(i=>{for(let t of i)if(t.url.includes(o)&&"focus"in t)return t.focus();if(t.clients.openWindow)return t.clients.openWindow(o)}))})})();